import React, { useContext } from 'react';
import { View, Text, FlatList, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';

export default function NotesScreen() {
  const { groups, user } = useContext(AppContext);

  const likedMessages = groups.flatMap((g) =>
    g.messages
      .filter((m) => m.likedRed?.some((u) => u.id === user?.id))
      .map((m) => ({ ...m, groupTitle: g.title }))
  );

  return (
    <View style={styles.container}>
      <Text style={[styles.title, { color: 'red' }]}>❤️ Notes</Text>
      <FlatList
        data={likedMessages}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={{ fontWeight: '600' }}>{item.groupTitle}</Text>
            <Text>{item.text}</Text>
            <Text style={{ color: '#666', fontSize: 12 }}>{new Date(item.createdAt).toLocaleString()}</Text>
          </View>
        )}
        ListEmptyComponent={<Text>ยังไม่มีโน้ตจากข้อความที่ถูกใจ</Text>}
      />
    </View>
  );
}

const styles = StyleSheet.create({ container: { flex: 1, padding: 12 }, title: { fontSize: 18, marginBottom: 8 }, item: { padding: 10, borderWidth: 1, borderColor: '#eee', borderRadius: 8, marginBottom: 8 } });
