import React, { useContext } from 'react';
import { View, Text, FlatList, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';

export default function CalendarScreen() {
  const { groups, user } = useContext(AppContext);

  // collect green-liked messages across all groups for current user
  const likedMessages = groups.flatMap((g) =>
    g.messages
      .filter((m) => m.likedGreen?.some((u) => u.id === user?.id))
      .map((m) => ({ ...m, groupTitle: g.title }))
  );

  // group by date
  const grouped = likedMessages.reduce((acc, msg) => {
    const date = new Date(msg.createdAt).toLocaleDateString();
    acc[date] = acc[date] || [];
    acc[date].push(msg);
    return acc;
  }, {});

  const sections = Object.keys(grouped).sort((a, b) => new Date(b) - new Date(a)).map((date) => ({ date, items: grouped[date] }));

  return (
    <View style={styles.container}>
      <Text style={[styles.title, { color: 'green' }]}>💚 Calender</Text>
      <FlatList
        data={sections}
        keyExtractor={(s) => s.date}
        renderItem={({ item }) => (
          <View style={styles.section}>
            <Text style={styles.date}>{item.date}</Text>
            {item.items.map((m) => (
              <View key={m.id} style={styles.item}>
                <Text style={{ fontWeight: '600' }}>{m.groupTitle}</Text>
                <Text>{m.text}</Text>
                <Text style={{ color: '#666', fontSize: 12 }}>{new Date(m.createdAt).toLocaleTimeString()}</Text>
              </View>
            ))}
          </View>
        )}
        ListEmptyComponent={<Text>ยังไม่มีข้อความที่คุณถูกใจ</Text>}
      />
    </View>
  );
}

const styles = StyleSheet.create({ container: { flex: 1, padding: 12 }, title: { fontSize: 18, marginBottom: 8 }, section: { marginBottom: 12 }, date: { fontSize: 16, fontWeight: '600', marginBottom: 6 }, item: { padding: 8, borderWidth: 1, borderColor: '#eee', borderRadius: 8, marginBottom: 6 } });
