import React from 'react';
import { View, Text, TouchableOpacity, Alert, StyleSheet } from 'react-native';
import theme from '../theme';

export default function ShareAppLink({ appUrl }) {
  const copyToClipboard = async () => {
    if (!appUrl) {
      Alert.alert('ยังไม่มีลิงก์', 'กรุณาใส่ลิงก์ที่ต้องการแชร์ใน src/config.js');
      return;
    }

    try {
      if (typeof navigator !== 'undefined' && navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(appUrl);
        Alert.alert('คัดลอกแล้ว', 'ลิงก์แอปถูกคัดลอกไปยังคลิปบอร์ด');
      } else {
        // Fallback: show the link so user can copy manually
        Alert.alert('คัดลอกลิงก์', appUrl);
      }
    } catch (e) {
      Alert.alert('ผิดพลาด', 'ไม่สามารถคัดลอกลิงก์ได้');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.label}>ลิงก์สำหรับแชร์:</Text>
      <Text style={styles.url} numberOfLines={1} ellipsizeMode="middle">
        {appUrl || 'ยังไม่ได้ตั้งค่า (ตั้งค่าใน src/config.js)'}
      </Text>
      <TouchableOpacity onPress={copyToClipboard} style={styles.button}>
        <Text style={styles.buttonText}>คัดลอกลิงก์</Text>
      </TouchableOpacity>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { padding: 12, backgroundColor: theme.background },
  label: { marginBottom: 6, color: theme.text },
  url: { color: theme.secondary, marginBottom: 8 },
  button: { backgroundColor: theme.button, paddingVertical: 8, paddingHorizontal: 12, borderRadius: 8, alignSelf: 'flex-start' },
  buttonText: { color: theme.text, fontWeight: '600' }
});
