import React, { useContext } from 'react';
import { View, Text, Button, FlatList, TouchableOpacity, StyleSheet } from 'react-native';
import { AppContext } from '../context/AppContext';
import theme from '../theme';
import ShareAppLink from '../components/ShareAppLink';
import CONFIG from '../config';

export default function HomeScreen({ navigation }) {
  const { user, groups } = useContext(AppContext);

  const myGroups = groups.filter((g) => g.members.find((m) => m.id === user?.id));

  return (
    <View style={styles.container}>
      <ShareAppLink appUrl={CONFIG.appUrl} />
      <Text style={styles.welcome}>ยินดีต้อนรับ, {user?.name}</Text>
      <View style={styles.row}>
        <TouchableOpacity style={styles.pillButton} onPress={() => navigation.navigate('CreateGroup')}>
          <Text style={styles.buttonText}>สร้างกลุ่ม</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.pillButton} onPress={() => navigation.navigate('JoinGroup')}>
          <Text style={styles.buttonText}>เข้าร่วมกลุ่ม</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.pillButton} onPress={() => navigation.navigate('Calendar')}>
          <Text style={styles.buttonText}>ปฎิทิน</Text>
        </TouchableOpacity>
        <TouchableOpacity style={styles.pillButton} onPress={() => navigation.navigate('Notes')}>
          <Text style={styles.buttonText}>โน้ต</Text>
        </TouchableOpacity>
      </View>

      <Text style={styles.section}>กลุ่มของฉัน</Text>
      <FlatList
        data={myGroups}
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <TouchableOpacity style={styles.groupItem} onPress={() => navigation.navigate('Chat', { groupId: item.id })}>
            <Text style={{ fontSize: 18, color: theme.text }}>{item.title}</Text>
            <Text style={{ color: theme.text }}>{item.members.length} สมาชิก</Text>
          </TouchableOpacity>
        )}
        ListEmptyComponent={<Text style={{ color: theme.text }}>ยังไม่มีสมาชิกในกลุ่มของคุณ</Text>}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 16, backgroundColor: theme.background },
  welcome: { fontSize: 20, marginBottom: 12, color: theme.text },
  row: { flexDirection: 'row', justifyContent: 'space-between', marginBottom: 12, flexWrap: 'wrap' },
  section: { fontSize: 16, marginTop: 12, marginBottom: 8, color: theme.text },
  groupItem: { padding: 12, borderWidth: 1, borderColor: theme.secondary, borderRadius: 8, marginBottom: 8 },
  pillButton: {
    backgroundColor: theme.button,
    borderRadius: 999,
    paddingVertical: 10,
    paddingHorizontal: 18,
    marginHorizontal: 6,
    minWidth: 120,
    alignItems: 'center',
    marginBottom: 8
  },
  buttonText: {
    color: theme.text,
    fontWeight: '600'
  }
});
